# -*- coding: utf-8 -*-
"""Fetch latest mail from nikita.sys@portkkm.ru via IMAP."""
import email
import imaplib
import ssl
import sys
from email.header import decode_header
from pathlib import Path

sys.stdout.reconfigure(encoding="utf-8", errors="replace")

USER = "nikita.sys@portkkm.ru"
# read password from desktop file
pw = None
for p in (
    Path(r"C:\Users\cherkasov.n\Desktop\pochta-nikita.sys.txt"),
    Path(r"E:\Data\Users\cherkasov.n\Desktop\pochta-nikita.sys.txt"),
):
    if p.exists():
        for line in p.read_text(encoding="utf-8").splitlines():
            if line.lower().startswith("пароль:"):
                pw = line.split(":", 1)[1].strip()
                break
if not pw:
    raise SystemExit("password file not found")

ctx = ssl.create_default_context()
# try 993 then 143 STARTTLS / plain


def dec(s):
    if s is None:
        return ""
    parts = decode_header(s)
    out = []
    for frag, enc in parts:
        if isinstance(frag, bytes):
            out.append(frag.decode(enc or "utf-8", "replace"))
        else:
            out.append(frag)
    return "".join(out)


def body_of(msg):
    if msg.is_multipart():
        texts = []
        htmls = []
        for part in msg.walk():
            ctype = part.get_content_type()
            disp = str(part.get("Content-Disposition") or "")
            if "attachment" in disp:
                continue
            try:
                payload = part.get_payload(decode=True) or b""
                charset = part.get_content_charset() or "utf-8"
                text = payload.decode(charset, "replace")
            except Exception:
                continue
            if ctype == "text/plain":
                texts.append(text)
            elif ctype == "text/html":
                htmls.append(text)
        return "\n".join(texts) if texts else "\n".join(htmls)
    payload = msg.get_payload(decode=True) or b""
    charset = msg.get_content_charset() or "utf-8"
    return payload.decode(charset, "replace")


hosts = ["mx.portkkm.ru", "192.168.2.140", "192.168.2.14"]
M = None
last_err = None
for host in hosts:
    for mode in ("ssl993", "starttls143", "plain143"):
        try:
            if mode == "ssl993":
                M = imaplib.IMAP4_SSL(host, 993, ssl_context=ctx, timeout=15)
            elif mode == "starttls143":
                M = imaplib.IMAP4(host, 143, timeout=15)
                M.starttls(ssl_context=ctx)
            else:
                M = imaplib.IMAP4(host, 143, timeout=15)
            M.login(USER, pw)
            print(f"OK {host} {mode}")
            break
        except Exception as e:
            last_err = f"{host} {mode}: {type(e).__name__}: {e}"
            M = None
    if M:
        break

if not M:
    raise SystemExit(f"IMAP fail: {last_err}")

typ, data = M.select("INBOX")
print("SELECT", typ, data)
typ, data = M.search(None, "ALL")
ids = data[0].split() if data and data[0] else []
print("COUNT", len(ids))
if not ids:
    # also check Junk / Spam
    for folder in ("Junk", "Spam", "Junk E-mail", "Корзина", "Trash"):
        try:
            typ, _ = M.select(folder)
            if typ != "OK":
                continue
            typ, data = M.search(None, "ALL")
            ids2 = data[0].split() if data and data[0] else []
            print(f"FOLDER {folder} count={len(ids2)}")
            if ids2:
                ids = ids2
                break
        except Exception as e:
            print("skip folder", folder, e)
if not ids:
    print("NO MESSAGES")
    M.logout()
    raise SystemExit(0)

# fetch last 5
for num in ids[-5:]:
    typ, msg_data = M.fetch(num, "(RFC822)")
    raw = msg_data[0][1]
    msg = email.message_from_bytes(raw)
    subj = dec(msg.get("Subject"))
    frm = dec(msg.get("From"))
    to = dec(msg.get("To"))
    date = msg.get("Date")
    body = body_of(msg)
    print("=" * 60)
    print("UID/NUM", num.decode())
    print("From:", frm)
    print("To:", to)
    print("Date:", date)
    print("Subject:", subj)
    print("-" * 40)
    print(body[:8000])
    print()

M.logout()

