import socket, struct, hashlib, binascii

def encode_len(n):
    if n < 0x80:
        return bytes([n])
    if n < 0x4000:
        return struct.pack(">H", n | 0x8000)
    if n < 0x200000:
        return struct.pack(">I", n | 0xC00000)[1:]
    if n < 0x10000000:
        return struct.pack(">I", n | 0xE0000000)
    return b"\xF0" + struct.pack(">I", n)

def encode_word(w):
    b = w.encode() if isinstance(w, str) else w
    return encode_len(len(b)) + b

def send_sentence(sock, words):
    sock.sendall(b"".join(encode_word(w) for w in words) + b"\x00")

def read_len(sock):
    c = sock.recv(1)
    if not c:
        raise EOFError
    b = c[0]
    if b & 0x80 == 0:
        return b
    if b & 0xC0 == 0x80:
        return ((b & 0x3F) << 8) + sock.recv(1)[0]
    if b & 0xE0 == 0xC0:
        x = sock.recv(2)
        return ((b & 0x1F) << 16) + (x[0] << 8) + x[1]
    if b & 0xF0 == 0xE0:
        x = sock.recv(3)
        return ((b & 0x0F) << 24) + (x[0] << 16) + (x[1] << 8) + x[2]
    if b & 0xF8 == 0xF0:
        return struct.unpack(">I", sock.recv(4))[0]
    raise ValueError("bad len")

def read_word(sock):
    n = read_len(sock)
    if n == 0:
        return None
    buf = b""
    while len(buf) < n:
        buf += sock.recv(n - len(buf))
    return buf.decode("utf-8", "replace")

def read_sentence(sock):
    words = []
    while True:
        w = read_word(sock)
        if w is None:
            break
        words.append(w)
    return words

def talk(host, user, password, cmds, port=8728):
    s = socket.create_connection((host, port), timeout=5)
    send_sentence(s, ["/login", "=name=" + user, "=password=" + password])
    r = read_sentence(s)
    if not r or r[0] != "!done":
        if any(x.startswith("=ret=") for x in r):
            chal = binascii.unhexlify([x for x in r if x.startswith("=ret=")][0][5:])
            md = hashlib.md5()
            md.update(b"\x00" + password.encode() + chal)
            send_sentence(s, ["/login", "=name=" + user, "=response=00" + md.hexdigest()])
            r = read_sentence(s)
            if not r or r[0] != "!done":
                s.close()
                return {"error": r}
        else:
            s.close()
            return {"error": r}
    out = []
    for cmd in cmds:
        send_sentence(s, cmd)
        while True:
            sen = read_sentence(s)
            out.append(sen)
            if sen and sen[0] in ("!done", "!trap", "!fatal"):
                break
    s.close()
    return out

creds = [
    ("PORTadmin", "NvO22eBZcj"),
    ("PORTadmin", "NvO 22 eBZcj"),
    ("Sysadmin", "vk4Y69TSQ2"),
    ("Sysadmin", "vk4Y69TSQ"),
    ("admin", ""),
]
cmds = [
    ["/ip/dhcp-server/lease/print", "?address=192.168.2.76"],
    ["/ip/arp/print", "?address=192.168.2.76"],
    ["/ip/dhcp-server/lease/print"],
]
for user, pwd in creds:
    try:
        res = talk("192.168.2.1", user, pwd, cmds)
        print("USER", user, "PWD_LEN", len(pwd), "RESULT")
        if isinstance(res, dict):
            print(res)
            continue
        for sen in res:
            line = " ".join(sen)
            if "192.168.2.76" in line or "2.76" in line or sen[0] in ("!trap", "!fatal") or "=address=" in line:
                if "192.168.2.7" in line or sen[0] in ("!trap", "!fatal", "!done"):
                    print(sen)
        # also print any lease with hostname containing print
        for sen in res:
            joined = " ".join(sen).lower()
            if "print" in joined or "hp" in joined or "kyocera" in joined or "xerox" in joined or "canon" in joined:
                print("PRINTER?", sen)
        break
    except Exception as e:
        print("USER", user, "FAIL", type(e).__name__, e)

