function L([string]$m) { [void]$log.Add($m); Write-Output $m }

L '=== BEFORE ==='
Get-Process | Where-Object { $_.ProcessName -match 'openvpn|ovpn|OpenVPNConnect' } |
  Group-Object ProcessName | ForEach-Object { L ("{0}={1}" -f $_.Name, $_.Count) }

$svcNames = @('OVPNConnectorService', 'agent_ovpnconnect', 'ovpnhelper_service')
foreach ($n in $svcNames) {
  $s = Get-Service -Name $n -ErrorAction SilentlyContinue
  if (-not $s) { L ("svc {0}: not found" -f $n); continue }
  try {
    if ($s.Status -ne 'Stopped') {
      Stop-Service -Name $n -Force -ErrorAction Stop
      L ("svc {0}: stopped" -f $n)
    } else {
      L ("svc {0}: already stopped" -f $n)
    }
  } catch {
    L ("svc {0} stop FAIL: {1}" -f $n, $_.Exception.Message)
  }
  try {
    Set-Service -Name $n -StartupType Disabled -ErrorAction Stop
    L ("svc {0}: Disabled" -f $n)
  } catch {
    $r = & sc.exe config $n start= disabled 2>&1 | Out-String
    L ("svc {0} Set-Service FAIL, sc: {1}" -f $n, $r)
  }
}

$names = @('OpenVPNConnect', 'agent_ovpnconnect', 'ovpnconnector', 'ovpnhelper_service', 'openvpn', 'openvpn-gui')
foreach ($n in $names) {
  $ps = Get-Process -Name $n -ErrorAction SilentlyContinue
  if ($ps) {
    $ps | Stop-Process -Force -ErrorAction SilentlyContinue
    L ("killed {0} x{1}" -f $n, $ps.Count)
  }
}
Start-Sleep 2

foreach ($k in @(
  'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Run',
  'HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Run'
)) {
  if (-not (Test-Path $k)) { continue }
  $item = Get-ItemProperty $k -ErrorAction SilentlyContinue
  $item.PSObject.Properties |
    Where-Object { $_.Name -notmatch '^PS' -and ($_.Name -match 'openvpn|ovpn' -or $_.Value -match 'openvpn|ovpn|OpenVPNConnect') } |
    ForEach-Object {
      try {
        Remove-ItemProperty -Path $k -Name $_.Name -Force -ErrorAction Stop
        L ("removed Run {0}\{1}" -f $k, $_.Name)
      } catch {
        L ("remove Run FAIL {0}: {1}" -f $_.Name, $_.Exception.Message)
      }
    }
}

Get-ChildItem 'Registry::HKEY_USERS' -ErrorAction SilentlyContinue | ForEach-Object {
  $sid = $_.PSChildName
  if ($sid -notmatch '^S-1-5-21-') { return }
  $run = "Registry::HKEY_USERS\$sid\Software\Microsoft\Windows\CurrentVersion\Run"
  if (-not (Test-Path $run)) { return }
  $item = Get-ItemProperty $run -ErrorAction SilentlyContinue
  $item.PSObject.Properties |
    Where-Object { $_.Name -notmatch '^PS' -and ($_.Name -match 'openvpn|ovpn' -or $_.Value -match 'openvpn|ovpn|OpenVPNConnect') } |
    ForEach-Object {
      try {
        Remove-ItemProperty -Path $run -Name $_.Name -Force -ErrorAction Stop
        L ("removed HKU\{0} Run {1}" -f $sid, $_.Name)
      } catch {
        L ("HKU remove FAIL: {0}" -f $_.Exception.Message)
      }
    }
}

# Disable launch-at-login in OpenVPN Connect settings if present
$settings = @(
  'C:\Users\MF\AppData\Roaming\OpenVPN Connect\settings.json',
  'C:\ProgramData\OpenVPN Connect\settings.json'
)
foreach ($f in $settings) {
  if (Test-Path $f) {
    L ("settings found: {0}" -f $f)
    try {
      $raw = Get-Content $f -Raw -Encoding UTF8
      L ("settings preview: {0}" -f $raw.Substring(0, [Math]::Min(800, $raw.Length)))
      $j = $raw | ConvertFrom-Json
      $changed = $false
      foreach ($prop in @('launchOnLogin', 'launch_on_login', 'opened-at-login', 'startOnLogin', 'autostart')) {
        if ($null -ne $j.PSObject.Properties[$prop]) {
          $j.$prop = $false
          $changed = $true
        }
      }
      if ($changed) {
        ($j | ConvertTo-Json -Depth 20) | Set-Content $f -Encoding UTF8
        L ("settings updated: {0}" -f $f)
      }
    } catch {
      L ("settings parse FAIL: {0}" -f $_.Exception.Message)
    }
  }
}

$cfg = 'C:\Program Files\OpenVPN Connect\ovpnconnector.cfg'
if (Test-Path $cfg) {
  L 'connector.cfg:'
  Get-Content $cfg -ErrorAction SilentlyContinue | ForEach-Object { L $_ }
}

L '=== AFTER SERVICES ==='
Get-Service -Name $svcNames -ErrorAction SilentlyContinue | ForEach-Object {
  L ("{0} Status={1} StartType={2}" -f $_.Name, $_.Status, $_.StartType)
}

L '=== AFTER PROCS ==='
$left = Get-Process | Where-Object { $_.ProcessName -match 'openvpn|ovpn|OpenVPNConnect' }
if ($left) {
  $left | ForEach-Object { L ("STILL: {0} pid={1}" -f $_.ProcessName, $_.Id) }
} else {
  L 'no openvpn processes'
}

L '=== STARTUP LEFT ==='
$st = Get-CimInstance Win32_StartupCommand -ErrorAction SilentlyContinue |
  Where-Object { $_.Command -match 'openvpn|ovpn' -or $_.Name -match 'openvpn|ovpn' }
if ($st) {
  $st | ForEach-Object { L ("startup still: {0} | {1} | {2}" -f $_.Name, $_.Command, $_.Location) }
} else {
  L 'no openvpn startup entries'
}

$ErrorActionPreference = 'Continue'

# Fix OpenVPN Connect settings: no autostart on reboot/login
$f = 'C:\Users\MF\AppData\Roaming\OpenVPN Connect\settings.json'
if (Test-Path $f) {
  $raw = Get-Content $f -Raw -Encoding UTF8
  $j = $raw | ConvertFrom-Json
  if ($j.openvpn) {
    if ($null -ne $j.openvpn.PSObject.Properties['connect:actionOnReboot']) {
      $j.openvpn.'connect:actionOnReboot' = 'none'
    }
    if ($null -ne $j.openvpn.PSObject.Properties['connect:launchOnLogin']) {
      $j.openvpn.'connect:launchOnLogin' = $false
    }
    # common keys
    foreach ($k in @('connect:startOnLogin','connect:autostart','connect:opened-at-login')) {
      if ($null -ne $j.openvpn.PSObject.Properties[$k]) { $j.openvpn.$k = $false }
    }
  }
  $json = $j | ConvertTo-Json -Depth 30
  Set-Content -Path $f -Value $json -Encoding UTF8
  Write-Output 'settings.json updated actionOnReboot=none'
  # verify
  $v = (Get-Content $f -Raw | ConvertFrom-Json).openvpn.'connect:actionOnReboot'
  Write-Output ("verify actionOnReboot={0}" -f $v)
}

# Clear connector "installed" flag so service won't auto-bind profile if re-enabled
$cfg = 'C:\Program Files\OpenVPN Connect\ovpnconnector.cfg'
if (Test-Path $cfg) {
  # UTF-16 LE based on earlier dump (spaces between chars)
  $bak = $cfg + '.bak_' + (Get-Date -Format 'yyyyMMdd_HHmmss')
  Copy-Item $cfg $bak -Force
  $content = @"
dco=N
is_installed=N
is_running=N
logfile_path=
profile_path=
security_level=legacy
vpn_protocol=tcp
"@
  Set-Content -Path $cfg -Value $content -Encoding Unicode
  Write-Output ("connector.cfg reset, backup={0}" -f $bak)
}

Write-Output '=== FINAL CHECK ==='
Get-Service -Name OVPNConnectorService,agent_ovpnconnect,ovpnhelper_service -ErrorAction SilentlyContinue |
  Format-Table Name,Status,StartType -Auto | Out-String
$p = Get-Process | Where-Object { $_.ProcessName -match 'openvpn|ovpn|OpenVPNConnect' }
if ($p) { $p | Format-Table Id,ProcessName -Auto | Out-String } else { Write-Output 'procs: none' }

$st = Get-CimInstance Win32_StartupCommand -ErrorAction SilentlyContinue |
  Where-Object { $_.Command -match 'openvpn|ovpn' -or $_.Name -match 'openvpn|ovpn' }
if ($st) { $st | Format-Table Name,Command -Auto | Out-String } else { Write-Output 'startup: none' }

# Why many instances? peek agent log
$alog = 'C:\Program Files\OpenVPN Connect\agent.log'
if (Test-Path $alog) {
  Write-Output '=== agent.log last 30 ==='
  Get-Content $alog -Tail 30 -ErrorAction SilentlyContinue
}
$clog = 'C:\ProgramData\OpenVPN\Port-Mol\firsov-connector.log'
if (Test-Path $clog) {
  Write-Output '=== connector log last 20 ==='
  Get-Content $clog -Tail 20 -ErrorAction SilentlyContinue
}

$ErrorActionPreference = 'Stop'

# Keep headless auto-connect OFF; allow GUI to start agent on demand
$svcMap = @{
  'OVPNConnectorService' = 'Disabled'   # no background auto-VPN
  'ovpnhelper_service'   = 'Manual'     # helper if GUI needs it
  'agent_ovpnconnect'    = 'Manual'     # agent started by GUI when needed
}
foreach ($n in $svcMap.Keys) {
  $s = Get-Service -Name $n -ErrorAction SilentlyContinue
  if (-not $s) { Write-Output ("missing {0}" -f $n); continue }
  if ($s.Status -ne 'Stopped') {
    Stop-Service -Name $n -Force -ErrorAction SilentlyContinue
  }
  Set-Service -Name $n -StartupType $svcMap[$n]
  Write-Output ("{0} -> Stopped / {1}" -f $n, $svcMap[$n])
}

# Ensure no login autostart
$runPaths = @()
Get-ChildItem 'Registry::HKEY_USERS' -ErrorAction SilentlyContinue | ForEach-Object {
  $sid = $_.PSChildName
  if ($sid -notmatch '^S-1-5-21-') { return }
  $run = "Registry::HKEY_USERS\$sid\Software\Microsoft\Windows\CurrentVersion\Run"
  if (Test-Path $run) {
    $item = Get-ItemProperty $run -ErrorAction SilentlyContinue
    $item.PSObject.Properties |
      Where-Object { $_.Name -notmatch '^PS' -and ($_.Name -match 'openvpn|ovpn' -or $_.Value -match 'OpenVPNConnect') } |
      ForEach-Object {
        Remove-ItemProperty -Path $run -Name $_.Name -Force -ErrorAction SilentlyContinue
        Write-Output ("removed Run {0}" -f $_.Name)
      }
  }
}

$settings = 'C:\Users\MF\AppData\Roaming\OpenVPN Connect\settings.json'
if (Test-Path $settings) {
  $j = Get-Content $settings -Raw -Encoding UTF8 | ConvertFrom-Json
  if ($j.openvpn) {
    $j.openvpn.'connect:actionOnReboot' = 'none'
  }
  ($j | ConvertTo-Json -Depth 30) | Set-Content $settings -Encoding UTF8
  Write-Output 'settings actionOnReboot=none'
}

# Shortcut: plain GUI, one instance (OpenVPN Connect itself is single-instance)
$exe = 'C:\Program Files\OpenVPN Connect\OpenVPNConnect.exe'
if (-not (Test-Path $exe)) { throw "OpenVPNConnect.exe not found" }

$desktopDirs = @(
  'C:\Users\MF\Desktop',
  'C:\Users\Public\Desktop'
) | Where-Object { Test-Path $_ }

$wsh = New-Object -ComObject WScript.Shell
foreach ($desk in $desktopDirs) {
  $lnkPath = Join-Path $desk 'OpenVPN Connect.lnk'
  $lnk = $wsh.CreateShortcut($lnkPath)
  $lnk.TargetPath = $exe
  $lnk.WorkingDirectory = 'C:\Program Files\OpenVPN Connect'
  $lnk.WindowStyle = 1
  $lnk.Description = 'OpenVPN Connect (один экземпляр, без автозапуска)'
  $lnk.IconLocation = "$exe,0"
  # no --opened-at-login, no args
  $lnk.Arguments = ''
  $lnk.Save()
  Write-Output ("shortcut: {0}" -f $lnkPath)
}

Write-Output '=== STATE (not starting app) ==='
Get-Service -Name OVPNConnectorService,agent_ovpnconnect,ovpnhelper_service |
  Format-Table Name,Status,StartType -Auto | Out-String
$p = Get-Process -Name OpenVPNConnect,agent_ovpnconnect,ovpnconnector -ErrorAction SilentlyContinue
if ($p) { $p | Format-Table Id,ProcessName -Auto | Out-String } else { Write-Output 'procs: none (as requested)' }

