input.contents:
$ErrorActionPreference = 'Continue'

# Agent + Helper: Manual so GUI/shortcut can start them
# Connector: keep Disabled (background auto-VPN)
Set-Service -Name agent_ovpnconnect -StartupType Manual
Set-Service -Name ovpnhelper_service -StartupType Manual
Set-Service -Name OVPNConnectorService -StartupType Disabled

# Start agent+helper so Connect can work; do NOT start OpenVPNConnect.exe
Start-Service -Name agent_ovpnconnect -ErrorAction SilentlyContinue
Start-Service -Name ovpnhelper_service -ErrorAction SilentlyContinue

Get-Service -Name agent_ovpnconnect,ovpnhelper_service,OVPNConnectorService |
  Format-Table Name,Status,StartType -Auto | Out-String

# Verify Manual services can be toggled
$ok = $true
foreach ($n in @('agent_ovpnconnect','ovpnhelper_service')) {
  $s = Get-Service $n
  if ($s.StartType -eq 'Disabled') { $ok = $false; Write-Output ("FAIL still Disabled: {0}" -f $n) }
  if ($s.Status -ne 'Running') {
    try { Start-Service $n -ErrorAction Stop; Write-Output ("started {0}" -f $n) }
    catch { Write-Output ("start {0}: {1}" -f $n, $_.Exception.Message); $ok = $false }
  }
}
if ($ok) { Write-Output 'OK: Agent+Helper Manual and startable. Connector Disabled. GUI not launched.' }

input.command:
$ip='26.170.19.123'; $sec=ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred=New-Object PSCredential('.\usr1cv8',$sec)
Invoke-Command -ComputerName $ip -Credential $cred -ScriptBlock {
  Get-Process OpenVPNConnect -EA SilentlyContinue | Stop-Process -Force
