  "procs=$((Get-Process OpenVPNConnect,agent_ovpnconnect,ovpnhelper_service -EA SilentlyContinue | Measure).Count)"
  Get-Service agent_ovpnconnect,ovpnhelper_service,OVPNConnectorService | ft Name,Status,StartType -Auto | Out-String
  $log='C:\Program Files\OpenVPN Connect\agent.log'
  if(Test-Path $log){ Get-Content $log -Tail 15 }
  $pl=Get-ChildItem 'C:\Users\MF\AppData\Roaming\OpenVPN Connect\logs\*.log' -EA SilentlyContinue | Sort LastWriteTime -Desc | Select -First 1
  if($pl){ "--- $($pl.Name) ---"; Get-Content $pl.FullName -Tail 25 }
}

$ip='26.170.19.123'; $sec=ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred=New-Object PSCredential('.\usr1cv8',$sec)
Invoke-Command -ComputerName $ip -Credential $cred -ScriptBlock {
  $ps = Get-CimInstance Win32_Process | Where-Object { $_.Name -match 'OpenVPNConnect|agent_ovpn|ovpnhelper|ovpnconnector' }
  "count=$($ps.Count)"
  $ps | Select-Object ProcessId,ParentProcessId,Name,@{n='Cmd';e={$_.CommandLine}} | Format-List | Out-String -Width 220
