  foreach ($p in $ps) {
    $parent = Get-CimInstance Win32_Process -Filter "ProcessId=$($p.ParentProcessId)" -EA SilentlyContinue
    "{0} pid={1} ppid={2} parent={3}" -f $p.Name,$p.ProcessId,$p.ParentProcessId,$(if($parent){$parent.Name}else{'?'})
  }
