  Get-Process OpenVPNConnect -EA SilentlyContinue | Select Id,MainWindowTitle,Handles,WorkingSet64 | Format-Table -Auto | Out-String
}

$ip='26.170.19.123'; $sec=ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred=New-Object PSCredential('.\usr1cv8',$sec)
Invoke-Command -ComputerName $ip -Credential $cred -ScriptBlock {
  $ErrorActionPreference='Continue'
  Write-Output '=== ovpn.log errors (last) ==='
  $log='C:\Users\MF\AppData\Roaming\OpenVPN Connect\log\ovpn.log'
  if(Test-Path $log){
    Select-String -Path $log -Pattern 'ERROR|AUTH|FAIL|TIMEOUT|fatal|hang|Unable|refused|TLS|EVENT:' | Select-Object -Last 30 | ForEach-Object { $_.Line }
    Write-Output '--- tail ---'
    Get-Content $log -Tail 40
  }
  Write-Output '=== settings connect keys ==='
  $s=Get-Content 'C:\Users\MF\AppData\Roaming\OpenVPN Connect\settings.json' -Raw | ConvertFrom-Json
  $s.openvpn.PSObject.Properties | Where-Object { $_.Name -match 'connect:|proxy|dco|proto|timeout|persist|auth|credential' } | ForEach-Object { "{0}={1}" -f $_.Name,$_.Value }

  Write-Output '=== auth files (user only, no secrets printed) ==='
  foreach($f in @(
    'C:\ProgramData\OpenVPN\Port-Mol\firsov-auth.txt',
    'C:\ProgramData\OpenVPN\Port-Mol\auth.txt',
    'C:\Program Files\OpenVPN Connect\auth.txt'
  )){
    if(Test-Path $f){
      $lines=@(Get-Content $f)
      "file=$f lines=$($lines.Count) user=$($lines[0]) pass_len=$(if($lines.Count -gt 1){$lines[1].Length}else{0})"
    }
  }

  Write-Output '=== TunPersist / drivers ==='
  Get-ChildItem 'C:\Users\MF\AppData\Roaming\OpenVPN Connect','C:\ProgramData\OpenVPN*' -Recurse -Filter '*persist*' -EA SilentlyContinue | Select FullName,Length,LastWriteTime
  Get-ChildItem 'C:\Program Files\OpenVPN Connect\drivers' -EA SilentlyContinue | ft Name -Auto | Out-String
  Get-NetAdapter | ? { $_.InterfaceDescription -match 'OpenVPN|TAP|Wintun|DCO' } | ft Name,Status,InterfaceDescription -Auto | Out-String

  Write-Output '=== NOW: is anything connecting? ==='
  Get-Process OpenVPNConnect -EA SilentlyContinue | measure | % { "OpenVPNConnect=$($_.Count)" }
  Get-NetUDPEndpoint -EA SilentlyContinue | ? { $_.LocalAddress -like '10.220.*' }
  Get-NetTCPConnection -RemoteAddress 95.188.79.98 -EA SilentlyContinue | ft State,LocalAddress,LocalPort,RemotePort,OwningProcess -Auto | Out-String
  Get-NetTCPConnection -RemoteAddress 46.166.66.105 -EA SilentlyContinue | ft State,LocalPort,RemotePort,OwningProcess -Auto | Out-String
}

$ip='26.170.19.123'; $sec=ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred=New-Object PSCredential('.\usr1cv8',$sec)
Invoke-Command -ComputerName $ip -Credential $cred -ScriptBlock {
  $ErrorActionPreference='Continue'
  # who owns SynSent
  Get-NetTCPConnection -RemotePort 1194 -EA SilentlyContinue | ForEach-Object {
    $p=Get-Process -Id $_.OwningProcess -EA SilentlyContinue
    "state=$($_.State) remote=$($_.RemoteAddress):$($_.RemotePort) pid=$($_.OwningProcess) name=$($p.ProcessName) path=$($p.Path)"
  }
  # probe both remotes with 3s timeout
  foreach($h in @('95.188.79.98','46.166.66.105')){
    $sw=[Diagnostics.Stopwatch]::StartNew()
    $ok=$false; $err=''
    try {
      $c=New-Object Net.Sockets.TcpClient
      $iar=$c.BeginConnect($h,1194,$null,$null)
      $ok=$iar.AsyncWaitHandle.WaitOne(3000,$false) -and $c.Connected
      if(-not $ok){ $c.Close(); $err='timeout' } else { $c.Close() }
    } catch { $err=$_.Exception.Message; $ok=$false }
    "{0}:1194 ok={1} ms={2} err={3}" -f $h,$ok,$sw.ElapsedMilliseconds,$err
  }

  # Fix GUI profile: only working remote, no remote-random
  $prof='C:\Users\MF\AppData\Roaming\OpenVPN Connect\profiles\1783910833349.ovpn'
  if(Test-Path $prof){
    Copy-Item $prof ($prof+'.bak_'+ (Get-Date -Format yyyyMMdd_HHmmss)) -Force
    $txt=Get-Content $prof -Raw
    $txt=$txt -replace '(?m)^remote 46\.166\.66\.105 1194 tcp\r?\n',''
    $txt=$txt -replace '(?m)^remote-random\r?\n',''
    Set-Content $prof $txt -Encoding UTF8
    Write-Output '=== profile remotes after fix ==='
    Select-String -Path $prof -Pattern '^(remote|proto|auth-user-pass|block-outside)' | ForEach-Object { $_.Line }
  }
  # also fix PORT-MOL-FIXED if needed
  Write-Output '=== adapters ==='
  Get-NetAdapter | ? { $_.InterfaceDescription -match 'OpenVPN|TAP|DCO' } | ft Name,Status,MacAddress -Auto | Out-String
}

$ip='26.170.19.123'; $sec=ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred=New-Object PSCredential('.\usr1cv8',$sec)
Invoke-Command -ComputerName $ip -Credential $cred -ScriptBlock {
