$ip='26.170.19.123'; $sec=ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred=New-Object PSCredential('.\usr1cv8',$sec)
Invoke-Command -ComputerName $ip -Credential $cred -ScriptBlock {
  $ErrorActionPreference='Continue'
  '=== config.json (profiles/creds hints) ==='
  $cj='C:\Users\MF\AppData\Roaming\OpenVPN Connect\config.json'
  if(Test-Path $cj){
    $raw=Get-Content $cj -Raw
    "len=$($raw.Length)"
    # redact passwords in output
    $safe=$raw -replace '("password"\s*:\s*")[^"]*(")','$1***$2' -replace '("passwd"\s*:\s*")[^"]*(")','$1***$2'
    if($safe.Length -gt 2500){ $safe.Substring(0,2500) } else { $safe }
  }

  # Kill hung GUI completely
  Get-Process OpenVPNConnect -EA SilentlyContinue | Stop-Process -Force
  Start-Sleep 1

  # Point auth-user-pass to known working auth file
  $auth='C:\\ProgramData\\OpenVPN\\Port-Mol\\firsov-auth.txt'
  $profs=@(
    'C:\Users\MF\AppData\Roaming\OpenVPN Connect\profiles\1783910833349.ovpn',
    'C:\Users\MF\AppData\Roaming\OpenVPN Connect\profiles\PORT-MOL-FIXED.ovpn',
    'C:\ProgramData\OpenVPN\Port-Mol\firsov-connector.ovpn'
  )
  foreach($p in $profs){
    if(-not (Test-Path $p)){ continue }
    $lines=Get-Content $p
    $out=@()
    $done=$false
    foreach($l in $lines){
      if($l -match '^\s*auth-user-pass(\s|$)'){
        $out += "auth-user-pass `"$auth`""
        $done=$true
      } else { $out += $l }
