$ip='26.41.66.35'
$sec=ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force
$cred=New-Object System.Management.Automation.PSCredential('.\usr1cv8',$sec)
Invoke-Command -ComputerName $ip -Credential $cred -Authentication Negotiate -ScriptBlock {
  $ErrorActionPreference='Continue'
  function L($m){ Write-Output "[$(Get-Date -Format 'HH:mm:ss')] $m" }

  L '=== fptr_t.cfg ==='
  # binary-ish? try both
  Format-Hex 'C:\Users\buh\AppData\Roaming\ATOL\drivers10\test\fptr_t.cfg' -Count 256 | Out-String
  Get-Content 'C:\Users\buh\AppData\Roaming\ATOL\drivers10\test\fptr_t.cfg' -Encoding Byte -TotalCount 20 | Out-String
  # try as text with different encodings
  [Text.Encoding]::UTF8.GetString([IO.File]::ReadAllBytes('C:\Users\buh\AppData\Roaming\ATOL\drivers10\test\fptr_t.cfg'))

  L '=== open KKT via Fptr10 COM ==='
  # Constants from ATOL docs
  $LIBFPTR_PARAM_PORT = 1  # might need actual constants
  # Use settings strings commonly used
  $fptr = New-Object -ComObject 'AddIn.Fptr10'

  # Discover methods via Type.InvokeMember is hard; try common pattern from ATOL docs:
  # setSingleSetting / applySingleSettings / open / isOpened / getParamString / getSettings / etc.

  $methods = @()
  try {
    # Late binding dump via ScriptControl not available; try known calls
    $null = $fptr | Get-Member -ErrorAction SilentlyContinue
  } catch {}

  # ATOL Fptr10 IDispatch methods often include:
  # setSingleSetting(key, value), applySingleSettings(), open(), close(), errorCode, errorDescription, getSettings
  # Setting keys: "Port", "ComFile", "BaudRate", "Model", "OfdChannel" ...
  function TryCall($obj, $name, $args){
    try {
      $r = $obj.GetType().InvokeMember($name, [Reflection.BindingFlags]::InvokeMethod, $null, $obj, $args)
      return @{ok=$true; r=$r}
    } catch {
      return @{ok=$false; err=$_.Exception.Message}
    }
  }
  function TryGet($obj, $name){
    try {
      $r = $obj.GetType().InvokeMember($name, [Reflection.BindingFlags]::GetProperty, $null, $obj, $null)
      return @{ok=$true; r=$r}
    } catch {
      return @{ok=$false; err=$_.Exception.Message}
    }
  }

  # Probe available
  foreach($m in @('setSingleSetting','applySingleSettings','open','close','isOpened','errorCode','errorDescription','getSettings','setSettings','processJson','showProperties','version')){
    $t = TryCall $fptr $m @()
    if($t.ok){ "CALL $m() -> $($t.r)" } else {
      # try as property
      $p = TryGet $fptr $m
      if($p.ok){ "PROP $m -> $($p.r)" } else { "NO $m" }
    }
  }

  # Try open with COM4
  $ports = @('COM4','COM3','4','3')
  foreach($port in $ports){
    L "trying port $port"
    $a = TryCall $fptr 'setSingleSetting' @('Port', '0') # COM
    $b = TryCall $fptr 'setSingleSetting' @('ComFile', $port)
    $c = TryCall $fptr 'setSingleSetting' @('BaudRate', '115200')
    $d = TryCall $fptr 'applySingleSettings' @()
    $e = TryCall $fptr 'open' @()
    $opened = TryCall $fptr 'isOpened' @()
    $err = TryGet $fptr 'errorDescription'
    $code = TryGet $fptr 'errorCode'
    "setPort=$($a.ok)/$($b.ok) apply=$($d.ok) open=$($e.ok) isOpened=$($opened.r) errCode=$($code.r) err=$($err.r)"
    if($opened.ok -and $opened.r){
      # read serial
      $js = TryCall $fptr 'processJson' @('{"type":"getDeviceInfo"}')
      "deviceInfo=$($js.r)"
      break
    }
    [void](TryCall $fptr 'close' @())
  }
}

