  param($b64)
  function L($m){ Write-Output "[$(Get-Date -Format 'HH:mm:ss')] $m" }
  # Check PIOT/ESM
  netstat -ano | findstr "LISTENING" | findstr "51401 51077 4041 5995" | ForEach-Object { L $_ }
  try {
    add-type @"
