    $r=Invoke-WebRequest 'https://127.0.0.1:51401/api/v1/info' -UseBasicParsing -TimeoutSec 8
    L ("PIOT "+$r.StatusCode+" "+$r.Content.Substring(0,[Math]::Min(180,$r.Content.Length)))
  } catch { L ("PIOT "+$_.Exception.Message) }

  # Soft approach: do NOT kill 1C yet - first check if COM hangs due to license by trying empty wrong user quickly
  [IO.File]::WriteAllBytes('C:\Users\Public\piot-probe.ps1',[Convert]::FromBase64String($b64))
  Remove-Item 'C:\Users\Public\piot-auth.log' -Force -EA SilentlyContinue

  # Kill thin client temporarily to free session, then COM, then restart
  $tc=Get-Process 1cv8c -EA SilentlyContinue
  $cmdLine=$null
  if($tc){
    $wmi=Get-CimInstance Win32_Process -Filter "ProcessId=$($tc.Id)"
    $cmdLine=$wmi.CommandLine
    L ("stopping 1cv8c cmd="+$cmdLine)
    Stop-Process -Id $tc.Id -Force
    Start-Sleep 3
  }

  $ps32="$env:SystemRoot\SysWOW64\WindowsPowerShell\v1.0\powershell.exe"
