  L ("probe "+$p.Id)
  $ok=$false
  for($i=0;$i -lt 24;$i++){
    Start-Sleep 10
    $alive=[bool](Get-Process -Id $p.Id -EA SilentlyContinue)
    $log=if(Test-Path 'C:\Users\Public\piot-auth.log'){(Get-Content 'C:\Users\Public\piot-auth.log' -Raw)}else{'nolog'}
    L ("t=$i alive=$alive $($log.Replace("`r`n",' | '))")
    if($log -match 'OK |ERR |DONE'){ $ok=$true; break }
    if(-not $alive){ break }
  }
  if(Get-Process -Id $p.Id -EA SilentlyContinue){ Stop-Process -Id $p.Id -Force; L 'timeout kill probe' }

  # Restart thin client in session 1 for user
  if($cmdLine){
    L "restarting 1C thin client"
    # Prefer IBName launch
    $exe='C:\Program Files (x86)\1cv8\8.5.1.1150\bin\1cv8c.exe'
    & 'C:\Users\Public\PsExec.exe' -accepteula -i 1 -d $exe ENTERPRISE '/IBNameБономар' 2>&1 | Out-Null
    L "restart issued"
  }
  if(Test-Path 'C:\Users\Public\piot-auth.log'){ Get-Content 'C:\Users\Public\piot-auth.log' -Encoding UTF8 | ForEach-Object { L "F $_" } }
} -ArgumentList $b64
